const input = $input.first().json;

const template_key = input.template_key || input.remotion_template || 'stat_callout';
let data_payload = input.data_payload || {};
if (typeof data_payload === 'string') {
  try { data_payload = JSON.parse(data_payload); } catch(e) { data_payload = {}; }
}

const color_mood = input.color_mood || 'neutral';
const format = input.format || 'png';
const scene_id = input.scene_id;
const scene_number = input.scene_number;
const topic_id = input.topic_id;
const project_id = input.project_id;
const drive_folder_id = input.drive_folder_id || 'root';
const style_dna = input.style_dna || '';

if (!scene_id) {
  throw new Error('scene_id is required');
}

return [{ json: {
  template_key,
  data_payload,
  color_mood,
  format,
  scene_id,
  scene_number,
  topic_id,
  project_id,
  drive_folder_id,
  style_dna,
  output_filename: `scene_${String(scene_number).padStart(3, '0')}.${format}`
} }];

const prep = $('Prepare Request').first().json;
const driveResult = $('Upload to Drive').first().json;

return [{ json: {
  success: true,
  scene_id: prep.scene_id,
  scene_number: prep.scene_number,
  topic_id: prep.topic_id,
  image_drive_id: driveResult.id || '',
  image_url: driveResult.webViewLink || driveResult.webContentLink || '',
  render_method: 'remotion',
  template_key: prep.template_key
} }];

const prep = $('Prepare Request').first().json;
const renderResponse = $('Call Render Service').first().json;

// PATCH scene as failed
const supabaseUrl = $env.SUPABASE_URL;
const anonKey = $env.SUPABASE_ANON_KEY;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;

try {
  await fetch(
    `${supabaseUrl}/rest/v1/scenes?id=eq.${prep.scene_id}`,
    {
      method: 'PATCH',
      headers: {
        'apikey': anonKey,
        'Authorization': `Bearer ${serviceKey}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({ image_status: 'failed' })
    }
  );
} catch(e) {
  // Logging best effort
}

return [{ json: {
  success: false,
  scene_id: prep.scene_id,
  scene_number: prep.scene_number,
  topic_id: prep.topic_id,
  error: renderResponse.error || renderResponse.message || 'Render service returned failure',
  render_method: 'remotion',
  template_key: prep.template_key
} }];
